import React from "react";

const toF = (c) => (c == null ? null : (c * 9) / 5 + 32);
const round = (x) => (x == null ? null : Math.round(x));

// Normalize probability-of-precipitation from either 0..1 or 0..100 -> 0..1
function normPop(p) {
  if (p == null || Number.isNaN(Number(p))) return null;
  let x = Number(p);
  if (x > 1) x = x / 100; // treat 42 as 0.42
  return Math.max(0, Math.min(1, x));
}
function fmtPop(p) {
  const x = normPop(p);
  if (x == null) return "—";
  return `${Math.round(x * 100)}%`;
}

// precipitation amount formatter (assume mm from most APIs; show “in” when imperial)
function fmtPrecipAmount(mm, unit) {
  if (mm == null) return "—";
  if (typeof mm !== "number") return "—";
  if (unit === "imperial") {
    const inches = mm / 25.4;
    return `${inches.toFixed(inches >= 1 ? 2 : 2)} in`;
  }
  return `${mm.toFixed(mm >= 1 ? 1 : 1)} mm`;
}

// ---- safely stringify weather label of any shape ----
function safeWeatherLabel(w) {
  if (w == null) return "—";
  if (Array.isArray(w) && w.length) {
    const first = w[0];
    if (typeof first === "string") return first;
    if (first && typeof first === "object") return first.description || first.main || "—";
    return "—";
  }
  if (typeof w === "object") return w.description || w.main || "—";
  return String(w);
}

export default function Forecast({ hourly = [], daily = [], daily16 = [], unit = "metric" }) {
  const fmtT = (c) => (unit === "imperial" ? round(toF(c)) : round(c));

  const hasHourly = Array.isArray(hourly) && hourly.length > 0;
  const hasDaily = Array.isArray(daily) && daily.length > 0;
  const hasExt = Array.isArray(daily16) && daily16.length > 0;

  return (
    <div className="space-y-6 text-white">
      {/* Hourly */}
      <section>
        <h2 className="text-lg font-semibold mb-2">Next Hours</h2>
        <div className="flex gap-3 overflow-x-auto pb-2">
          {hasHourly ? (
            hourly.map((h, idx) => (
              <div key={h.dt ?? idx} className="shrink-0 rounded-2xl px-3 py-2 bg-black/40 backdrop-blur">
                <div className="text-sm">
                  {new Date((h.dt ?? Date.now() / 1000) * 1000).toLocaleTimeString([], { hour: "numeric" })}
                </div>
                <div className="text-center text-2xl">{fmtT(h.temp)}°</div>
                <div className="text-xs opacity-80">{fmtPop(h.pop)}</div>
                {/* NEW: precip amount */}
                <div className="text-[11px] opacity-75 mt-0.5">
                  {fmtPrecipAmount(h.precipitation, unit)}
                </div>
              </div>
            ))
          ) : (
            <div className="opacity-70 text-sm">No hourly data.</div>
          )}
        </div>
      </section>

      {/* Daily */}
      <section>
        <h2 className="text-lg font-semibold mb-2">Daily</h2>
        <div className="flex flex-col gap-2">
          {hasDaily ? (
            daily.map((d, idx) => {
              const label = safeWeatherLabel(d.weather);
              return (
                <div
                  key={d.dt ?? idx}
                  className="w-full rounded-2xl px-4 py-3 bg-black/40 backdrop-blur flex items-center justify-between"
                >
                  <div className="w-36">
                    <div className="font-medium">
                      {new Date((d.dt ?? Date.now() / 1000) * 1000).toLocaleDateString(undefined, { weekday: "short" })}
                    </div>
                    <div className="text-xs opacity-80 truncate">{label}</div>
                  </div>
                  <div className="flex-1 text-right">
                    {fmtT(d.min)}° / <strong>{fmtT(d.max)}°</strong>
                  </div>
                  <div className="w-32 text-right text-sm opacity-75">
                    {fmtPop(d.pop)}
                    {/* NEW: show daily precip amount if available */}
                    {typeof d.precipitation === "number" && (
                      <span className="ml-2 text-[11px] opacity-80">
                        {fmtPrecipAmount(d.precipitation, unit)}
                      </span>
                    )}
                  </div>
                </div>
              );
            })
          ) : (
            <div className="opacity-70 text-sm">No daily data.</div>
          )}
        </div>
      </section>

      {/* Extended (16‑day) */}
      <section>
        <h2 className="text-lg font-semibold mb-2">16‑Day Forecast</h2>
        <div className="flex flex-col gap-2">
          {hasExt ? (
            daily16.map((d, i) => {
              const min = d?.temp?.min ?? d.min;
              const max = d?.temp?.max ?? d.max;
              const label = safeWeatherLabel(d.weather ?? d.description);
              return (
                <div
                  key={`${d.dt ?? i}-${i}`}
                  className="w-full rounded-2xl px-4 py-3 bg-black/40 backdrop-blur flex items-center justify-between"
                >
                  <div className="w-44 pr-2">
                    <div className="font-medium">
                      {new Date((d.dt ?? Date.now() / 1000) * 1000).toLocaleDateString(undefined, {
                        weekday: "short",
                        month: "short",
                        day: "numeric",
                      })}
                    </div>
                    <div className="text-xs opacity-80 truncate">{label}</div>
                  </div>
                  <div className="flex-1 text-right">
                    {fmtT(min)}° / <strong>{fmtT(max)}°</strong>
                  </div>
                  <div className="w-32 text-right text-sm opacity-75">
                    {fmtPop(d.pop)}
                    {typeof d.precipitation === "number" && (
                      <span className="ml-2 text-[11px] opacity-80">
                        {fmtPrecipAmount(d.precipitation, unit)}
                      </span>
                    )}
                  </div>
                </div>
              );
            })
          ) : (
            <div className="opacity-70 text-sm">No extended forecast available.</div>
          )}
        </div>
      </section>
    </div>
  );
}
